const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const client_id = body.client_id || null;
const agent_id = body.agent_id || null;
const date = body.date || new Date().toISOString().slice(0, 10);
if (!client_id) return { json: { _error: true, error: 'client_id required', ok: false } };
return { json: { client_id, agent_id, date } };

const arr = $input.item.json || [];
const c = Array.isArray(arr) && arr.length > 0 ? arr[0] : null;
const parsed = $('Parse Input').first().json;
if (!c) return { json: { _error: true, error: 'client not found', ok: false } };
if (!c.travel_optimization_enabled) return { json: { _skip: true, reason: 'travel_optimization_enabled=false', ok: false, client_id: parsed.client_id } };
return { json: Object.assign({}, parsed, { base_latitude: c.base_latitude, base_longitude: c.base_longitude, speed_kmh: c.preferred_drive_speed_kmh || 40 }) };

// Haversine nearest-neighbour from base.
const rows = Array.isArray($input.item.json) ? $input.item.json : [];
const ctx = $('Validate Client').first().json;
const speed = ctx.speed_kmh || 40;

function haversine(lat1, lon1, lat2, lon2) {
  if (lat1 == null || lon1 == null || lat2 == null || lon2 == null) return null;
  const R = 6371.0;
  const toRad = function(x) { return x * Math.PI / 180; };
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a = Math.sin(dLat / 2) ** 2 + Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLon / 2) ** 2;
  return 2 * R * Math.asin(Math.sqrt(a));
}

const geo = rows.filter(function(r) { return r.latitude != null && r.longitude != null; });
if (geo.length < 2) {
  return { json: { _skip: true, skip_reason: 'fewer than 2 geocoded appointments', ok: false, client_id: ctx.client_id } };
}

// Baseline ('before'): trust chronological order
let kmBefore = 0;
let prev = (ctx.base_latitude != null && ctx.base_longitude != null) ? { latitude: ctx.base_latitude, longitude: ctx.base_longitude } : geo[0];
for (const r of geo) {
  const d = haversine(prev.latitude, prev.longitude, r.latitude, r.longitude);
  if (d != null) kmBefore += d;
  prev = r;
}

// Nearest-neighbour ordering starting from base
const remaining = geo.slice();
const ordered = [];
let current = { latitude: ctx.base_latitude, longitude: ctx.base_longitude };
if (current.latitude == null || current.longitude == null) {
  current = remaining.shift();
  ordered.push(current);
}
while (remaining.length > 0) {
  let bestIdx = 0, bestD = Infinity;
  for (let i = 0; i < remaining.length; i++) {
    const d = haversine(current.latitude, current.longitude, remaining[i].latitude, remaining[i].longitude);
    if (d != null && d < bestD) { bestD = d; bestIdx = i; }
  }
  current = remaining.splice(bestIdx, 1)[0];
  ordered.push(current);
}

let kmAfter = 0;
let p2 = (ctx.base_latitude != null && ctx.base_longitude != null) ? { latitude: ctx.base_latitude, longitude: ctx.base_longitude } : ordered[0];
for (const r of ordered) {
  const d = haversine(p2.latitude, p2.longitude, r.latitude, r.longitude);
  if (d != null) kmAfter += d;
  p2 = r;
}

const minBefore = Math.round((kmBefore / speed) * 60);
const minAfter  = Math.round((kmAfter  / speed) * 60);

return { json: {
  ok: true,
  client_id: ctx.client_id,
  agent_id: ctx.agent_id,
  date: ctx.date,
  ordered_appointment_ids: ordered.map(function(r) { return r.appointment_id; }),
  route_geometry: ordered.map(function(r) { return [r.latitude, r.longitude]; }),
  total_km_before: Number(kmBefore.toFixed(2)),
  total_km_after: Number(kmAfter.toFixed(2)),
  total_minutes_before: minBefore,
  total_minutes_after: minAfter,
  saved_minutes: Math.max(minBefore - minAfter, 0)
} };

// Build response — unify both IF branches.
const ctx = $('Haversine Optimize').first().json || {};
if (ctx._skip) {
  return { json: { ok: false, error: ctx.skip_reason || 'skipped' } };
}
const resp = $input.item.json;
let route_log_id = null;
if (typeof resp === 'string') route_log_id = resp;
else if (resp && resp.id) route_log_id = resp.id;
else if (Array.isArray(resp) && resp.length > 0 && resp[0].record_route_optimization) route_log_id = resp[0].record_route_optimization;
return { json: Object.assign({ ok: true, route_log_id }, {
  ordered_appointment_ids: ctx.ordered_appointment_ids,
  total_km_before: ctx.total_km_before,
  total_km_after: ctx.total_km_after,
  saved_minutes: ctx.saved_minutes
}) };
